/**
 * Leads Stats Filter Block
 *
 * Button+Badge clickable filters for the target lead list block.
 * Table: nb_crm_leads
 */

const TARGET_BLOCK_UID = 'b3f6e318381';

const { useState, useEffect } = ctx.React;
const { Button, Badge, Space, Spin } = ctx.antd;

const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.leads', ...opts });

// ==================== Stat Buttons Config ====================
const STATS = [
  { key: 'all', label: t('All Leads'), filter: null },
  { key: 'new', label: t('New'), filter: { status: 'new' } },
  { key: 'working', label: t('Working'), filter: { status: 'working' } },
  { key: 'qualified', label: t('Qualified'), filter: { status: 'qualified' } },
  { key: 'unqualified', label: t('Unqualified'), filter: { status: 'unqualified' } },
];

// ==================== Data Hook ====================
function useStats() {
  const [counts, setCounts] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const results = await Promise.all(
          STATS.map(s => ctx.api.request({
            url: 'nb_crm_leads:list',
            params: { pageSize: 1, ...(s.filter && { filter: JSON.stringify(s.filter) }) },
          }))
        );
        const c = {};
        STATS.forEach((s, i) => { c[s.key] = results[i]?.data?.meta?.count || 0; });
        setCounts(c);
      } catch (e) { console.error('Stats fetch failed:', e); }
      setLoading(false);
    };
    fetch();
  }, []);

  return { counts, loading };
}

// ==================== Main Component ====================
const StatsFilter = () => {
  const { counts, loading } = useStats();
  const [active, setActive] = useState('all');

  const handleClick = async (stat) => {
    setActive(stat.key);
    try {
      const target = ctx.engine?.getModel(TARGET_BLOCK_UID);
      if (!target) { ctx.message?.warning('Target block not found'); return; }
      target.resource.addFilterGroup(ctx.model.uid, stat.filter || { $and: [] });
      await target.resource.refresh();
    } catch (e) { console.error('Filter failed:', e); }
  };

  if (loading) return <Spin size="small" />;

  return (
    <Space wrap size={[8, 8]}>
      {STATS.map(s => (
        <Button key={s.key} type={active === s.key ? 'primary' : 'default'} onClick={() => handleClick(s)}>
          {s.label}{' '}
          <Badge count={counts[s.key] ?? 0} showZero overflowCount={9999}
            style={{ marginLeft: 4,
              backgroundColor: active === s.key ? '#fff' : '#f0f0f0',
              color: active === s.key ? '#1677ff' : 'rgba(0,0,0,0.65)',
              boxShadow: 'none' }} />
        </Button>
      ))}
    </Space>
  );
};

ctx.render(<StatsFilter />);

/**
 * Lead Info Column (Multi-field)
 *
 * Displays lead name with company in a combined cell.
 * - Primary: Lead name (bold)
 *   - If converted: clickable -> opens converted contact/customer detail
 *   - If not converted: plain text
 * - Secondary: Company name (gray, smaller)
 *
 * Table: nb_crm_leads
 * Fields: name, company, converted_contact_id, converted_customer_id
 */

const { Tooltip, Typography, Space } = ctx.antd;
const { Text, Link } = Typography;

// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.leads', ...opts });

// ==================== Config ====================
// Detail popup view UIDs
const CONTACT_DETAIL_VIEW_UID = 'zxsog8ixwmu';  // Contact detail view
const CUSTOMER_DETAIL_VIEW_UID = 'wsb6b480gtj';  // Customer detail view

// ==================== Styles ====================
const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    gap: 2,
    minWidth: 120,
  },
  placeholder: {
    fontSize: 13,
    color: T.colorTextTertiary || '#9ca3af',
    fontStyle: 'italic',
  },
};

// ==================== Component ====================
const LeadInfoColumn = () => {
  const record = ctx.record || {};
  const name = record.name || '';
  const company = record.company || '';

  // Check if converted
  const convertedContactId = record.converted_contact_id;
  const convertedCustomerId = record.converted_customer_id;
  const hasConvertedContact = !!convertedContactId;
  const hasConvertedCustomer = !!convertedCustomerId;

  // Click name to open contact detail (only clickable when converted to contact)
  const handleNameClick = async (e) => {
    e.stopPropagation();
    if (!hasConvertedContact || !convertedContactId) return;

    if (ctx.openView && CONTACT_DETAIL_VIEW_UID && CONTACT_DETAIL_VIEW_UID !== 'xxxxxxxxxx') {
      try {
        await ctx.openView(CONTACT_DETAIL_VIEW_UID, {
          mode: 'drawer',
          size: 'large',
          collectionName: 'nb_crm_contacts',
          dataSourceKey: 'main',
          filterByTk: convertedContactId,
        });
      } catch (err) {
        console.error('Failed to open contact detail:', err);
      }
    }
  };

  // Click company to open customer detail (only clickable when converted to customer)
  const handleCompanyClick = async (e) => {
    e.stopPropagation();
    if (!hasConvertedCustomer || !convertedCustomerId) return;

    if (ctx.openView && CUSTOMER_DETAIL_VIEW_UID && CUSTOMER_DETAIL_VIEW_UID !== 'xxxxxxxxxx') {
      try {
        await ctx.openView(CUSTOMER_DETAIL_VIEW_UID, {
          mode: 'drawer',
          size: 'large',
          collectionName: 'nb_crm_customers',
          dataSourceKey: 'main',
          filterByTk: convertedCustomerId,
        });
      } catch (err) {
        console.error('Failed to open customer detail:', err);
      }
    }
  };

  if (!name && !company) {
    return <span style={styles.placeholder}>—</span>;
  }

  const tooltipLines = [
    name && t('Name: {{name}}', { name: name }),
    company && t('Company: {{company}}', { company: company }),
  ];
  if (hasConvertedContact) {
    tooltipLines.push('Converted to Contact (click to view)');
  }
  if (hasConvertedCustomer) {
    tooltipLines.push('Converted to Customer (click to view)');
  }
  const tooltipContent = tooltipLines.filter(Boolean).join('\n');

  return (
    <Tooltip title={tooltipContent}>
      <div style={styles.container}>
        {name && (hasConvertedContact ? (
          <Link
            strong
            onClick={handleNameClick}
            style={{ fontSize: 14, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
          >
            {name}
          </Link>
        ) : (
          <Text
            strong
            style={{ fontSize: 14, color: T.colorText || '#111827', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
          >
            {name}
          </Text>
        ))}
        {company && (hasConvertedCustomer ? (
          <Link
            onClick={handleCompanyClick}
            style={{ fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
          >
            {company}
          </Link>
        ) : (
          <Text
            type="secondary"
            style={{ fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
          >
            {company}
          </Text>
        ))}
      </div>
    </Tooltip>
  );
};

// ==================== Render ====================
ctx.render(<LeadInfoColumn />);

/**
 * Lead Name Duplicate Check Input
 *
 * Core Features:
 *   - Uses resource API to check for duplicate names in nb_crm_leads
 *   - Debounce 500ms to prevent frequent queries
 *   - Shows first 3 duplicates in compact inline format
 *   - Two-level warning system:
 *     - Yellow warning: Only name matches (single field duplicate)
 *     - Red error: Both name AND company match (high confidence duplicate)
 *   - Maintains bidirectional binding with form value (ctx.getValue/ctx.setValue)
 *
 * Table: nb_crm_leads
 * Field: name (primary), company (cross-check)
 */

const { useState, useEffect, useRef, useCallback } = ctx.React;
const { Input, Spin, Typography, Alert } = ctx.antd;
const { Text } = Typography;

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.leads', ...opts });

// ==================== Config ====================
const COLLECTION = 'nb_crm_leads';
const CHECK_FIELD = 'name';
const DISPLAY_FIELDS = ['id', 'name', 'company'];
const DEBOUNCE_MS = 500;        // Debounce delay in ms
const MAX_DISPLAY = 3;          // Max duplicates to display
const MIN_SEARCH_LENGTH = 1;    // Min search length

// ==================== Helper Functions ====================
/**
 * Get the company field value from the current form context
 * Try multiple methods for compatibility with different form contexts
 */
const getFormCompanyValue = () => {
  // Method 1: via ctx.form (NocoBase common pattern)
  if (ctx.form?.getFieldValue) {
    const val = ctx.form.getFieldValue('company');
    if (val !== undefined && val !== null) return val;
  }

  // Method 2: via ctx.form.values
  if (ctx.form?.values?.company !== undefined) {
    return ctx.form.values.company;
  }

  // Method 3: via ctx.record (edit mode)
  if (ctx.record?.company !== undefined) {
    return ctx.record.company;
  }

  // Method 4: via ctx.formValues
  if (ctx.formValues?.company !== undefined) {
    return ctx.formValues.company;
  }

  return null;
};

/**
 * Normalize string for comparison (lowercase, trim)
 */
const normalizeString = (str) => {
  if (!str) return '';
  return String(str).toLowerCase().trim();
};

// ==================== Main Component ====================
const NameDuplicateCheck = () => {
  // Bidirectional binding with form value
  const [value, setValue] = useState(ctx.getValue?.() || '');
  const [duplicates, setDuplicates] = useState([]);
  const [loading, setLoading] = useState(false);
  const [totalCount, setTotalCount] = useState(0);

  // Debounce timer reference
  const debounceRef = useRef(null);
  // Current record ID (exclude self when editing)
  const currentRecordId = ctx.record?.id;

  // ==================== Check Duplicate Names ====================
  // Check for duplicate names and cross-check with company field
  const checkDuplicates = useCallback(async (searchName) => {
    // Clear previous results
    if (!searchName || searchName.length < MIN_SEARCH_LENGTH) {
      setDuplicates([]);
      setTotalCount(0);
      return;
    }

    setLoading(true);

    try {
      // Build filter conditions: fuzzy match on name field
      const filter = {
        [CHECK_FIELD]: { $includes: searchName }
      };

      // Exclude current record in edit mode
      if (currentRecordId) {
        filter.id = { $ne: currentRecordId };
      }

      // Call resource API to query
      const result = await ctx.api.request({
        url: `${COLLECTION}:list`,
        method: 'get',
        params: {
          filter: filter,
          pageSize: MAX_DISPLAY + 1,  // Query one more to check if there are more
          fields: DISPLAY_FIELDS,
        },
      });

      const data = result?.data?.data || [];
      const total = result?.data?.meta?.count || data.length;

      // Get current form's company value for cross-validation
      const currentCompany = getFormCompanyValue();
      const normalizedCurrentCompany = normalizeString(currentCompany);
      const normalizedSearchName = normalizeString(searchName);

      // Process data: mark match type
      // - isHighConfidence: name + company both match (high confidence duplicate)
      // - isNameMatch: name only match
      const processedData = data.slice(0, MAX_DISPLAY).map(item => {
        const normalizedItemName = normalizeString(item.name);
        const normalizedItemCompany = normalizeString(item.company);

        // Check if name is an exact match (case-insensitive)
        const isExactNameMatch = normalizedItemName === normalizedSearchName;

        // Check if company matches (requires both form and record to have company values)
        const isCompanyMatch = normalizedCurrentCompany &&
                               normalizedItemCompany &&
                               normalizedItemCompany === normalizedCurrentCompany;

        // High confidence: exact name match + company match
        const isHighConfidence = isExactNameMatch && isCompanyMatch;

        return {
          ...item,
          isExactNameMatch,
          isCompanyMatch,
          isHighConfidence,
        };
      });

      // Sort: high confidence first, then exact matches
      processedData.sort((a, b) => {
        if (a.isHighConfidence && !b.isHighConfidence) return -1;
        if (!a.isHighConfidence && b.isHighConfidence) return 1;
        if (a.isExactNameMatch && !b.isExactNameMatch) return -1;
        if (!a.isExactNameMatch && b.isExactNameMatch) return 1;
        return 0;
      });

      setDuplicates(processedData);
      setTotalCount(total);
    } catch (error) {
      console.error('Name duplicate check failed:', error);
      setDuplicates([]);
      setTotalCount(0);
    } finally {
      setLoading(false);
    }
  }, [currentRecordId]);

  // ==================== Debounced Input Change Handler ====================
  const handleChange = (e) => {
    const newValue = e.target.value;
    setValue(newValue);

    // Sync to form (bidirectional binding)
    ctx.setValue?.(newValue);

    // Clear previous debounce timer
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    // Set new debounce timer
    debounceRef.current = setTimeout(() => {
      checkDuplicates(newValue);
    }, DEBOUNCE_MS);
  };

  // ==================== Watch for External Value Changes ====================
  useEffect(() => {
    const handler = (ev) => {
      const next = ev?.detail ?? '';
      setValue(next);
      checkDuplicates(next);
    };
    ctx.element?.addEventListener('js-field:value-change', handler);
    return () => ctx.element?.removeEventListener('js-field:value-change', handler);
  }, [checkDuplicates]);

  // ==================== Cleanup Timer ====================
  useEffect(() => {
    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, []);

  // ==================== Render Compact Warning ====================
  const renderCompactWarning = () => {
    if (duplicates.length === 0) return null;

    // Check if there are high confidence duplicates (name + company match)
    const hasHighConfidence = duplicates.some(d => d.isHighConfidence);

    // Format duplicate items as compact list
    const formatItem = (item) => {
      if (item.isHighConfidence) {
        // High confidence: show as "Name @ Company"
        return `${item.name || 'Unnamed'} @ ${item.company}`;
      }
      // Normal: show as "Name (Company)"
      const company = item.company ? ` (${item.company})` : '';
      return `${item.name || 'Unnamed'}${company}`;
    };

    // Build display text
    const displayItems = duplicates.slice(0, MAX_DISPLAY).map(formatItem);
    const remaining = totalCount - MAX_DISPLAY;
    const itemsText = displayItems.join(', ') + (remaining > 0 ? t(', +{{remaining}} more', { remaining: remaining }) : '');

    // Choose type and prefix based on match type
    const alertType = hasHighConfidence ? 'error' : 'warning';
    const prefix = hasHighConfidence ? 'Duplicate' : 'Similar';

    return (
      <Alert
        type={alertType}
        message={`${prefix}: ${itemsText}`}
        showIcon
        style={{ marginTop: 4, padding: '4px 8px' }}
        banner
      />
    );
  };

  // ==================== Render Component ====================
  return (
    <div style={{ width: '100%' }}>
      <Input
        value={value}
        onChange={handleChange}
        placeholder={t('Enter lead name')}
        allowClear
        status={duplicates.some(d => d.isHighConfidence) ? 'error' :
                duplicates.length > 0 ? 'warning' : undefined}
        suffix={loading ? <Spin size="small" /> : null}
      />
      {renderCompactWarning()}
    </div>
  );
};

ctx.render(<NameDuplicateCheck />);

/**
 * Lead Company Duplicate Check Input
 *
 * Core Features:
 *   - Uses resource API to check for duplicate companies in nb_crm_leads
 *   - Debounce 500ms to prevent frequent queries
 *   - Shows first 3 duplicates in compact inline format
 *   - Two-level warning system:
 *     - Yellow warning: Only company matches (single field duplicate)
 *     - Red error: Both company AND name match the same record (high confidence duplicate)
 *   - Cross-checks with name field value for enhanced duplicate detection
 *   - Maintains bidirectional binding with form value (ctx.getValue/ctx.setValue)
 *
 * Table: nb_crm_leads
 * Field: company
 */

const { useState, useEffect, useRef, useCallback } = ctx.React;
const { Input, Spin, Typography, Alert } = ctx.antd;
const { Text } = Typography;

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.leads', ...opts });

// ==================== Config ====================
const COLLECTION = 'nb_crm_leads';
const CHECK_FIELD = 'company';
const DISPLAY_FIELDS = ['id', 'name', 'company'];
const DEBOUNCE_MS = 500;        // Debounce delay in ms
const MAX_DISPLAY = 3;          // Max duplicates to display
const MIN_SEARCH_LENGTH = 1;    // Min search length

// ==================== Helper Functions ====================
/**
 * Get the name field value from the form for cross-checking
 * Try multiple methods for compatibility with different form contexts
 */
const getNameFieldValue = () => {
  // Method 1: via ctx.form.getFieldValue
  if (ctx.form?.getFieldValue) {
    const nameValue = ctx.form.getFieldValue('name');
    if (nameValue) return nameValue;
  }

  // Method 2: via ctx.form.values
  if (ctx.form?.values?.name) {
    return ctx.form.values.name;
  }

  // Method 3: via ctx.record (edit mode)
  if (ctx.record?.name) {
    return ctx.record.name;
  }

  // Method 4: via formContext
  if (ctx.formContext?.values?.name) {
    return ctx.formContext.values.name;
  }

  return null;
};

/**
 * Compare two strings for similarity (case-insensitive, trimmed)
 */
const isSimilarString = (str1, str2) => {
  if (!str1 || !str2) return false;
  const s1 = str1.toString().trim().toLowerCase();
  const s2 = str2.toString().trim().toLowerCase();
  return s1 === s2;
};

// ==================== Main Component ====================
const CompanyDuplicateCheck = () => {
  // Bidirectional binding with form value
  const [value, setValue] = useState(ctx.getValue?.() || '');
  const [duplicates, setDuplicates] = useState([]);
  const [loading, setLoading] = useState(false);
  const [totalCount, setTotalCount] = useState(0);

  // Debounce timer reference
  const debounceRef = useRef(null);
  // Current record ID (exclude self when editing)
  const currentRecordId = ctx.record?.id;

  // ==================== Check Duplicate Companies ====================
  const checkDuplicates = useCallback(async (searchCompany) => {
    // Clear previous results
    if (!searchCompany || searchCompany.length < MIN_SEARCH_LENGTH) {
      setDuplicates([]);
      setTotalCount(0);
      return;
    }

    setLoading(true);

    try {
      // Build filter conditions: fuzzy match on company name
      const filter = {
        [CHECK_FIELD]: { $includes: searchCompany }
      };

      // Exclude current record in edit mode
      if (currentRecordId) {
        filter.id = { $ne: currentRecordId };
      }

      // Call resource API to query
      const result = await ctx.api.request({
        url: `${COLLECTION}:list`,
        method: 'get',
        params: {
          filter: filter,
          pageSize: MAX_DISPLAY + 1,  // Query one more to check if there are more
          fields: DISPLAY_FIELDS,
        },
      });

      const data = result?.data?.data || [];
      const total = result?.data?.meta?.count || data.length;

      // Get current name field value for cross-checking
      const currentName = getNameFieldValue();

      // Mark match level:
      // - isHighRisk: company AND name both match - high probability duplicate
      // - isCompanyMatch: company exact match
      const processedData = data.slice(0, MAX_DISPLAY).map(item => {
        const companyMatches = isSimilarString(item[CHECK_FIELD], searchCompany);
        const nameMatches = currentName && isSimilarString(item.name, currentName);

        return {
          ...item,
          // High risk duplicate: company and name both match the same record
          isHighRisk: companyMatches && nameMatches,
          // Company exact match
          isCompanyExact: companyMatches,
        };
      });

      // Sort: high risk first, then company exact matches
      processedData.sort((a, b) => {
        // High risk first
        if (a.isHighRisk && !b.isHighRisk) return -1;
        if (!a.isHighRisk && b.isHighRisk) return 1;
        // Then exact matches
        if (a.isCompanyExact && !b.isCompanyExact) return -1;
        if (!a.isCompanyExact && b.isCompanyExact) return 1;
        return 0;
      });

      setDuplicates(processedData);
      setTotalCount(total);
    } catch (error) {
      console.error('Company duplicate check failed:', error);
      setDuplicates([]);
      setTotalCount(0);
    } finally {
      setLoading(false);
    }
  }, [currentRecordId]);

  // ==================== Debounced Input Change Handler ====================
  const handleChange = (e) => {
    const newValue = e.target.value;
    setValue(newValue);

    // Sync to form (bidirectional binding)
    ctx.setValue?.(newValue);

    // Clear previous debounce timer
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    // Set new debounce timer
    debounceRef.current = setTimeout(() => {
      checkDuplicates(newValue);
    }, DEBOUNCE_MS);
  };

  // ==================== Watch for External Value Changes ====================
  useEffect(() => {
    const handler = (ev) => {
      const next = ev?.detail ?? '';
      setValue(next);
      checkDuplicates(next);
    };
    ctx.element?.addEventListener('js-field:value-change', handler);
    return () => ctx.element?.removeEventListener('js-field:value-change', handler);
  }, [checkDuplicates]);

  // ==================== Cleanup Timer ====================
  useEffect(() => {
    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, []);

  // ==================== Render Compact Warning ====================
  const renderCompactWarning = () => {
    if (duplicates.length === 0) return null;

    // Check if there are high risk duplicates (company + name both match)
    const hasHighRisk = duplicates.some(d => d.isHighRisk);

    // Format duplicate items as compact list
    const formatItem = (item) => {
      if (item.isHighRisk) {
        // High risk: show as "Name @ Company"
        return `${item.name || 'Unnamed'} @ ${item.company}`;
      }
      // Normal: show as "Name (Company)"
      const name = item.name || 'Unnamed';
      const company = item.company ? ` (${item.company})` : '';
      return `${name}${company}`;
    };

    // Build display text
    const displayItems = duplicates.slice(0, MAX_DISPLAY).map(formatItem);
    const remaining = totalCount - MAX_DISPLAY;
    const itemsText = displayItems.join(', ') + (remaining > 0 ? t(', +{{remaining}} more', { remaining: remaining }) : '');

    // Choose type and prefix based on match type
    const alertType = hasHighRisk ? 'error' : 'warning';
    const prefix = hasHighRisk ? 'Duplicate' : 'Similar';

    return (
      <Alert
        type={alertType}
        message={`${prefix}: ${itemsText}`}
        showIcon
        style={{ marginTop: 4, padding: '4px 8px' }}
        banner
      />
    );
  };

  // ==================== Render Component ====================
  return (
    <div style={{ width: '100%' }}>
      <Input
        value={value}
        onChange={handleChange}
        placeholder={t('Enter company name')}
        allowClear
        status={duplicates.some(d => d.isHighRisk) ? 'error' :
                duplicates.length > 0 ? 'warning' : undefined}
        suffix={loading ? <Spin size="small" /> : null}
      />
      {renderCompactWarning()}
    </div>
  );
};

ctx.render(<CompanyDuplicateCheck />);

/**
 * Lead Email Duplicate Check Input
 *
 * Core Features:
 *   - Uses resource API to check for duplicate emails in nb_crm_leads
 *   - Debounce 500ms to prevent frequent queries
 *   - Shows first 3 duplicates in compact inline format
 *   - Maintains bidirectional binding with form value (ctx.getValue/ctx.setValue)
 *
 * Table: nb_crm_leads
 * Field: email
 */

const { useState, useEffect, useRef, useCallback } = ctx.React;
const { Input, Spin, Typography, Alert } = ctx.antd;
const { Text } = Typography;

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.leads', ...opts });

// ==================== Config ====================
const COLLECTION = 'nb_crm_leads';
const CHECK_FIELD = 'email';
const DISPLAY_FIELDS = ['id', 'name', 'email'];
const DEBOUNCE_MS = 500;        // Debounce delay in ms
const MAX_DISPLAY = 3;          // Max duplicates to display
const MIN_SEARCH_LENGTH = 1;    // Min search length

// ==================== Main Component ====================
const EmailDuplicateCheck = () => {
  // Bidirectional binding with form value
  const [value, setValue] = useState(ctx.getValue?.() || '');
  const [duplicates, setDuplicates] = useState([]);
  const [loading, setLoading] = useState(false);
  const [totalCount, setTotalCount] = useState(0);

  // Debounce timer reference
  const debounceRef = useRef(null);
  // Current record ID (exclude self when editing)
  const currentRecordId = ctx.record?.id;

  // ==================== Check Duplicate Emails ====================
  const checkDuplicates = useCallback(async (searchEmail) => {
    // Clear previous results
    if (!searchEmail || searchEmail.length < MIN_SEARCH_LENGTH) {
      setDuplicates([]);
      setTotalCount(0);
      return;
    }

    setLoading(true);

    try {
      // Build filter conditions: fuzzy match on email
      const filter = {
        [CHECK_FIELD]: { $includes: searchEmail }
      };

      // Exclude current record in edit mode
      if (currentRecordId) {
        filter.id = { $ne: currentRecordId };
      }

      // Call resource API to query
      const result = await ctx.api.request({
        url: `${COLLECTION}:list`,
        method: 'get',
        params: {
          filter: filter,
          pageSize: MAX_DISPLAY + 1,  // Query one more to check if there are more
          fields: DISPLAY_FIELDS,
        },
      });

      const data = result?.data?.data || [];
      const total = result?.data?.meta?.count || data.length;

      // Mark exact match and fuzzy match
      const processedData = data.slice(0, MAX_DISPLAY).map(item => ({
        ...item,
        isExactMatch: item[CHECK_FIELD]?.toLowerCase() === searchEmail.toLowerCase(),
      }));

      // Exact matches first
      processedData.sort((a, b) => {
        if (a.isExactMatch && !b.isExactMatch) return -1;
        if (!a.isExactMatch && b.isExactMatch) return 1;
        return 0;
      });

      setDuplicates(processedData);
      setTotalCount(total);
    } catch (error) {
      console.error('Duplicate check failed:', error);
      setDuplicates([]);
      setTotalCount(0);
    } finally {
      setLoading(false);
    }
  }, [currentRecordId]);

  // ==================== Debounced Input Change Handler ====================
  const handleChange = (e) => {
    const newValue = e.target.value;
    setValue(newValue);

    // Sync to form (bidirectional binding)
    ctx.setValue?.(newValue);

    // Clear previous debounce timer
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    // Set new debounce timer
    debounceRef.current = setTimeout(() => {
      checkDuplicates(newValue);
    }, DEBOUNCE_MS);
  };

  // ==================== Watch for External Value Changes ====================
  useEffect(() => {
    const handler = (ev) => {
      const next = ev?.detail ?? '';
      setValue(next);
      checkDuplicates(next);
    };
    ctx.element?.addEventListener('js-field:value-change', handler);
    return () => ctx.element?.removeEventListener('js-field:value-change', handler);
  }, [checkDuplicates]);

  // ==================== Cleanup Timer ====================
  useEffect(() => {
    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, []);

  // ==================== Render Compact Warning ====================
  const renderCompactWarning = () => {
    if (duplicates.length === 0) return null;

    const hasExactMatch = duplicates.some(d => d.isExactMatch);

    // Format duplicate items as compact list
    const formatItem = (item) => {
      const name = item.name || 'Unnamed';
      const company = item.company ? ` (${item.company})` : '';
      return `${name}${company}`;
    };

    // Build display text
    const displayItems = duplicates.slice(0, MAX_DISPLAY).map(formatItem);
    const remaining = totalCount - MAX_DISPLAY;
    const itemsText = displayItems.join(', ') + (remaining > 0 ? t(', +{{remaining}} more', { remaining: remaining }) : '');

    // Choose type and prefix based on match type
    const alertType = hasExactMatch ? 'error' : 'warning';
    const prefix = hasExactMatch ? 'Duplicate' : 'Similar';

    return (
      <Alert
        type={alertType}
        message={`${prefix}: ${itemsText}`}
        showIcon
        style={{ marginTop: 4, padding: '4px 8px' }}
        banner
      />
    );
  };

  // ==================== Render Component ====================
  return (
    <div style={{ width: '100%' }}>
      <Input
        value={value}
        onChange={handleChange}
        placeholder={t('Enter email address')}
        type="email"
        allowClear
        status={duplicates.some(d => d.isExactMatch) ? 'error' :
                duplicates.length > 0 ? 'warning' : undefined}
        suffix={loading ? <Spin size="small" /> : null}
      />
      {renderCompactWarning()}
    </div>
  );
};

