    setDuplicates([]);
    setTotalCount(0);

    // Skip query if input is too short
    if (!value || value.length < DUPLICATE_CHECK_CONFIG.minSearchLength) {
      return;
    }

    // Set debounce timer
    timerRef.current = setTimeout(() => {
      performCheck(value);
    }, DUPLICATE_CHECK_CONFIG.debounceMs);
  }, [performCheck]);

  // Cleanup timer
  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearTimeout(timerRef.current);
      }
    };
  }, []);

  return {
