  if (!date) return 'No Date';

  const now = new Date();
  const target = new Date(date);
  const diffMs = now - target;

  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffHour = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffHour / 24);

  // Helper for pluralization (e.g., "1 day" vs "2 days")
  const pluralize = (num, unit) => `${num} ${unit}${num !== 1 ? 's' : ''} ago`;

  if (diffSec < 60) return 'Just now';
  if (diffMin < 60) return pluralize(diffMin, 'minute');
  if (diffHour < 24) return pluralize(diffHour, 'hour');
  if (diffDay === 1) return 'Yesterday';
  if (diffDay < 7) return pluralize(diffDay, 'day');
  if (diffDay < 30) return pluralize(Math.floor(diffDay / 7), 'week');
  if (diffDay < 365) return pluralize(Math.floor(diffDay / 30), 'month');

  return pluralize(Math.floor(diffDay / 365), 'year');
};

