    display: inline-block;
    font-size: 13px;
    color: ${style.color};
    background: transparent;
    padding: 2px 6px;
    border-radius: 3px;
    transition: all 0.2s ease;
  " title="${tooltipText}">
    ${relativeText}
  </div>
`;

